#include <threads.h>
#include <hardware.h>
#include <terminals.h>

#ifndef TERMINAL_MAX_LINE
#define TERMINAL_MAX_LINE 200
#endif

#define ERROR (-1)
#define ECHO_QUEUE_CAP 4096
#define INPUT_QUEUE_CAP 8192

enum tx_owner {
    TX_NONE = 0,
    TX_ECHO,
    TX_WRITER
};

struct term_state {
    int initialized;

    struct termstat stats;

    char edit_line[TERMINAL_MAX_LINE];
    int edit_len;

    char cooked_q[INPUT_QUEUE_CAP];
    int cooked_head;
    int cooked_tail;
    int cooked_count;
    int cooked_lines;

    char echo_q[ECHO_QUEUE_CAP];
    int echo_head;
    int echo_tail;
    int echo_count;

    int tx_busy;
    int writer_active;
    char *writer_buf;
    int writer_len;
    int writer_pos;
    int writer_need_lf;
    int writer_outstanding;

    enum tx_owner current_tx_owner;

    cond_id_t cv_readable;
    cond_id_t cv_writer_turn;
    cond_id_t cv_writer_done;
};

static int driver_initialized;
static struct term_state terms[NUM_TERMINALS];

static int
valid_term(int term)
{
    return term >= 0 && term < NUM_TERMINALS;
}

static void
enqueue_echo_char(int term, char c)
{
    struct term_state *t = &terms[term];

    if (t->echo_count >= ECHO_QUEUE_CAP) {
        return;
    }

    t->echo_q[t->echo_tail] = c;
    t->echo_tail = (t->echo_tail + 1) % ECHO_QUEUE_CAP;
    t->echo_count++;
}

static int
dequeue_echo_char(int term, char *c)
{
    struct term_state *t = &terms[term];

    if (t->echo_count == 0) {
        return 0;
    }

    *c = t->echo_q[t->echo_head];
    t->echo_head = (t->echo_head + 1) % ECHO_QUEUE_CAP;
    t->echo_count--;
    return 1;
}

static int
enqueue_cooked_char(int term, char c)
{
    struct term_state *t = &terms[term];

    if (t->cooked_count >= INPUT_QUEUE_CAP) {
        return 0;
    }

    t->cooked_q[t->cooked_tail] = c;
    t->cooked_tail = (t->cooked_tail + 1) % INPUT_QUEUE_CAP;
    t->cooked_count++;
    if (c == '\\n') {
        t->cooked_lines++;
    }

    return 1;
}

static int
dequeue_cooked_char(int term, char *c)
{
    struct term_state *t = &terms[term];

    if (t->cooked_count == 0) {
        return 0;
    }

    *c = t->cooked_q[t->cooked_head];
    t->cooked_head = (t->cooked_head + 1) % INPUT_QUEUE_CAP;
    t->cooked_count--;
    if (*c == '\\n') {
        t->cooked_lines--;
    }

    return 1;
}

static int
writer_has_more_output(int term)
{
    struct term_state *t = &terms[term];

    if ("'!t->writer_active) {
        return 0;
    }

    return (t->writer_need_lf || t->writer_pos < t->writer_len);
}

static int
writer_is_done(int term)
{
    struct term_state *t = &terms[term];

    if (!t->writer_active) {
        return 0;
    }

    return (t->writer_pos >= t->writer_len &&
            !t->writer_need_lf &&
            t->writer_outstanding == 0);
}

static void
send_char_to_hardware(int term, char c, enum tx_owner owner)
{
    struct term_state *t = &terms[term];

    WriteDataRegister(term, c);
    t->stats.tty_out++;
    t->tx_busy = 1;
    t->current_tx_owner = owner;
    if (owner == TX_WRITER) {
        t->writer_outstanding++;
    }
}

static void
kick_transmitter(int term)
{
    struct term_state *t = &terms[term];
    char out;
    char src;

    if (!t->initialized || t->tx_busy) {
        return;
    }

    if (dequeue_echo_char(term, &out)) {
        send_char_to_hardware(term, out, TX_ECHO);
        return;
    }

    if (!writer_has_more_output(term)) {
        return;
    }

    if (t->writer_need_lf) {
        out = '"'\\n';
        t->writer_need_lf = 0;
    } else {
        src = t->writer_buf[t->writer_pos++];
        if (src == '\\n') {
            out = '\\r';
            t->writer_need_lf = 1;
        } else {
            out = src;
        }
    }

    send_char_to_hardware(term, out, TX_WRITER);
}

int
InitTerminalDriver(void)
{
    int i;

    Declare_Monitor_Entry_Procedure();

    if (driver_initialized) {
        return ERROR;
    }

    driver_initialized = 1;
    for (i = 0; i < NUM_TERMINALS; i++) {
        terms[i].initialized = 0;
        terms[i].stats.tty_in = -1;
        terms[i].stats.tty_out = -1;
        terms[i].stats.user_in = -1;
        terms[i].stats.user_out = -1;

        terms[i].edit_len = 0;
        terms[i].cooked_head = 0;
        terms[i].cooked_tail = 0;
        terms[i].cooked_count = 0;
        terms[i].cooked_lines = 0;

        terms[i].echo_head = 0;
        terms[i].echo_tail = 0;
        terms[i].echo_count = 0;

        terms[i].tx_busy = 0;
        terms[i].writer_active = 0;
        terms[i].writer_buf = 0;
        terms[i].writer_len = 0;
        terms[i].writer_pos = 0;
        terms[i].writer_need_lf = 0;
        terms[i].writer_outstanding = 0;
        terms[i].current_tx_owner = TX_NONE;

        terms[i].cv_readable = CondCreate();
        terms[i].cv_writer_turn = CondCreate();
        terms[i].cv_writer_done = CondCreate();
    }

    return 0;
}

int
InitTerminal(int term)
{
    struct term_state *t;

    Declare_Monitor_Entry_Procedure();

    if ("'!driver_initialized || !valid_term(term)) {
        return ERROR;
    }

    t = &terms[term];
    if (t->initialized) {
        return ERROR;
    }

    if (InitHardware(term) == ERROR) {
        return ERROR;
    }

    t->initialized = 1;
    t->stats.tty_in = 0;
    t->stats.tty_out = 0;
    t->stats.user_in = 0;
    t->stats.user_out = 0;

    t->edit_len = 0;
    t->cooked_head = 0;
    t->cooked_tail = 0;
    t->cooked_count = 0;
    t->cooked_lines = 0;

    t->echo_head = 0;
    t->echo_tail = 0;
    t->echo_count = 0;

    t->tx_busy = 0;
    t->writer_active = 0;
    t->writer_buf = 0;
    t->writer_len = 0;
    t->writer_pos = 0;
    t->writer_need_lf = 0;
    t->writer_outstanding = 0;
    t->current_tx_owner = TX_NONE;

    return 0;
}

int
ReadTerminal(int term, char *buf, int buflen)
{
    struct term_state *t;
    int copied;
    char c;

    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized || !valid_term(term) || buf == 0 || buflen < 0) {
        return ERROR;
    }

    t = &terms[term];
    if (!t->initialized) {
        return ERROR;
    }

    if (buflen == 0) {
        return 0;
    }

    while (t->cooked_lines == 0) {
        CondWait(t->cv_readable);
    }

    copied = 0;
    while (copied < buflen && dequeue_cooked_char(term, &c)) {
        buf[copied++] = c;
        if (c == '"'\\n') {
            break;
        }
    }

    t->stats.user_out += copied;
    return copied;
}

int
WriteTerminal(int term, char *buf, int buflen)
{
    struct term_state *t;

    Declare_Monitor_Entry_Procedure();

    if ("'!driver_initialized || !valid_term(term) || buf == 0 || buflen < 0) {
        return ERROR;
    }

    t = &terms[term];
    if (!t->initialized) {
        return ERROR;
    }

    while (t->writer_active) {
        CondWait(t->cv_writer_turn);
    }

    t->writer_active = 1;
    t->writer_buf = buf;
    t->writer_len = buflen;
    t->writer_pos = 0;
    t->writer_need_lf = 0;
    t->writer_outstanding = 0;

    t->stats.user_in += buflen;

    kick_transmitter(term);

    while (!writer_is_done(term)) {
        CondWait(t->cv_writer_done);
    }

    t->writer_active = 0;
    t->writer_buf = 0;
    t->writer_len = 0;
    t->writer_pos = 0;
    t->writer_need_lf = 0;
    t->writer_outstanding = 0;

    CondSignal(t->cv_writer_turn);

    return buflen;
}

int
TerminalDriverStatistics(struct termstat *stats)
{
    int i;

    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized || stats == 0) {
        return ERROR;
    }

    for (i = 0; i < NUM_TERMINALS; i++) {
        stats[i] = terms[i].stats;
    }

    return 0;
}

void
ReceiveInterrupt(int term)
{
    struct term_state *t;
    char c;
    int i;

    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized || !valid_term(term)) {
        return;
    }

    t = &terms[term];
    if (!t->initialized) {
        return;
    }

    c = ReadDataRegister(term);
    t->stats.tty_in++;

    if (c == '"'\\r' || c == '\\n') {
        enqueue_echo_char(term, '\\r');
        enqueue_echo_char(term, '\\n');

        if (t->edit_len < TERMINAL_MAX_LINE) {
            t->edit_line[t->edit_len++] = '\\n';
        }

        for (i = 0; i < t->edit_len; i++) {
            enqueue_cooked_char(term, t->edit_line[i]);
        }
        t->edit_len = 0;

        CondSignal(t->cv_readable);
    } else if (c == '\\b' || c == '\\177') {
        if (t->edit_len > 0) {
            t->edit_len--;
            enqueue_echo_char(term, '\\b');
            enqueue_echo_char(term, ' ');
            enqueue_echo_char(term, '\\b');
        }
    } else {
        if (t->edit_len < TERMINAL_MAX_LINE) {
            t->edit_line[t->edit_len++] = c;
            enqueue_echo_char(term, c);
        }
    }

    kick_transmitter(term);
}

void
TransmitInterrupt(int term)
{
    struct term_state *t;

    Declare_Monitor_Entry_Procedure();

    if ("'!driver_initialized || !valid_term(term)) {
        return;
    }

    t = &terms[term];
    if (!t->initialized) {
        return;
    }

    if (t->tx_busy && t->current_tx_owner == TX_WRITER && t->writer_outstanding > 0) {
        t->writer_outstanding--;
    }

    t->tx_busy = 0;
    t->current_tx_owner = TX_NONE;

    if (writer_is_done(term)) {
        CondSignal(t->cv_writer_done);
    }

    kick_transmitter(term);

    if (writer_is_done(term)) {
        CondSignal(t->cv_writer_done);
    }
}
