    for (i = 0; i < NUM_TERMINALS; i++) {
        stats[i] = terms[i].stats;
    }

    return 0;
}

void
ReceiveInterrupt(int term)
{
    struct term_state *t;
    char c;
    int i;

    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized || !valid_term(term)) {
        return;
    }

    t = &terms[term];
    if (!t->initialized) {
        return;
    }

    c = ReadDataRegister(term);
    t->stats.tty_in++;

    if (c == '\r' || c == '\n') {
        enqueue_echo_char(term, '\r');
        enqueue_echo_char(term, '\n');

        if (t->edit_len < TERMINAL_MAX_LINE) {
            t->edit_line[t->edit_len++] = '\n';
        }

        for (i = 0; i < t->edit_len; i++) {
            enqueue_cooked_char(term, t->edit_line[i]);
        }
        t->edit_len = 0;

        CondSignal(t->cv_readable);
    } else if (c == '\b' || c == '\177') {
        if (t->edit_len > 0) {
            t->edit_len--;
            enqueue_echo_char(term, '\b');
            enqueue_echo_char(term, ' ');
            enqueue_echo_char(term, '\b');
        }
    } else {
        if (t->edit_len < TERMINAL_MAX_LINE) {
            t->edit_line[t->edit_len++] = c;
            enqueue_echo_char(term, c);
        }
    }

    kick_transmitter(term);
}

void
TransmitInterrupt(int term)
{
    struct term_state *t;

    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized || !valid_term(term)) {
        return;
    }

    t = &terms[term];
    if (!t->initialized) {
        return;
    }

    if (t->tx_busy && t->current_tx_owner == TX_WRITER && t->writer_outstanding > 0) {
        t->writer_outstanding--;
    }

    t->tx_busy = 0;
    t->current_tx_owner = TX_NONE;

    if (writer_is_done(term)) {
        CondSignal(t->cv_writer_done);
    }

    kick_transmitter(term);

    if (writer_is_done(term)) {
        CondSignal(t->cv_writer_done);
    }
}
